import{_ as a,o as t,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"87. Allied Health Manager Structure","description":"","frontmatter":{"title":"87. Allied Health Manager Structure","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/87-allied-health-manager-structure.md","filePath":"ebas/allied-health/classification-staffing/87-allied-health-manager-structure.md"}'),n={name:"ebas/allied-health/classification-staffing/87-allied-health-manager-structure.md"};function o(s,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_87-allied-health-manager-structure" tabindex="-1">87. Allied Health Manager Structure <a class="header-anchor" href="#_87-allied-health-manager-structure" aria-label="Permalink to &quot;87. Allied Health Manager Structure&quot;">​</a></h1><p><strong>87.1</strong> For the purposes of classifying all Allied Health Manager and Assistant Allied Health Manager positions it will be necessary to divide the number of hours worked by relevant Employees (including interns) or total staff as the case may be, in that department by 38 with any fraction being taken to the next whole number.</p><p><strong>87.2</strong> Classifying Allied Health Manager positions When classifying Allied Health Manager positions in:</p><p><strong>(a)</strong> Cardiac Technology (Cardiac Physiology);</p><p><strong>(b)</strong> Health Information Management (Medical Records Administration);</p><p><strong>(c)</strong> Medical Imaging Technology (Radiography);</p><p><strong>(d)</strong> Medical Library;</p><p><strong>(e)</strong> Music Therapy;</p><p><strong>(f)</strong> Nuclear Medicine Technology;</p><p><strong>(g)</strong> Occupational Therapy;</p><p><strong>(h)</strong> Orthoptics;</p><p><strong>(i)</strong> Orthotics/Prosthetics;</p><p><strong>(j)</strong> Photography or Illustration (Medical Photography or Illustration);</p><p><strong>(k)</strong> Physiotherapy;</p><p><strong>(l)</strong> Podiatry;</p><p><strong>(m)</strong> Radiation Therapy Technology (Radiation Therapy);</p><p><strong>(n)</strong> Recreation Therapy;</p><p><strong>(o)</strong> Research Technology;</p><p><strong>(p)</strong> Social Work; and</p><p><strong>(q)</strong> Speech Pathology; an Employee who would have been a Chief (as defined in the 2011 Agreement) classified two (2) grades or more below that of another Chief position (that is either in the therapy stream or the radiation related stream) in the employ of the same Employer under the 2011 Agreement, will be reclassified as described at subclause 87.3 (Reclassification) below.</p><p><strong>87.3</strong> Reclassification</p><p><strong>(a)</strong> This clause 87 is to have the same effect as subclause 29.1 of the 2011 Agreement, subclause 86.3 of the 2016 Agreement and subclause 86.3 of the 2020 Agreement.</p><p><strong>(b)</strong> The Grade 6 Allied Health Manager has no impact on reclassification under this clause 87.</p><p><strong>(c)</strong> A translation table intending to give effect to subclause 87.3(a) taking into account the AHP1 classification structure is outlined as follows (different FTE numbers AHP apply to Orthotics/Prosthetics): 2011 Agreement 2016 Agreement, 2020 Agreement, and this Agreement</p><p>Allied Health Chief Staff Reclassification Staff Equivalent translation Manager (AHM)</p><p>Chief 1 – 5 FTE AHP Where an allied chief AHM Grade 1 – 5 FTE AHP and/or Where another AHM is Grade 1 and/or at least 6 is a Chief Grade 3, 4 3 6 – 14 other staff Grade 4, 5 or 6, the other staff or 5 the Chief Grade AHM Grade 3 must be 1 would be reclassified to the reclassified to Chief Grade 3 Year 4 Grade 2 increment if they are at a lower increment in Grade 3.</p><p>Chief 6 – 14 FTE AHP Where an allied Chief AHM Grade 6 – 14 FTE AHP Where another AHM is Grade 2 and/or at least 15 is a Chief Grade 4 or 3 and/or 15 – 25 other Grade 4 (and in charge other staff 5 the Chief Grade 2 staff of 25 – 39 FTE AHP would be reclassified and/or 28 – 45 other to Chief Grade 3 staff), 5 or 6, the AHM Grade 3 must be reclassified to Grade 4.</p><p>Chief 15 – 24 FTE AHP Where an allied Chief AHM Grade 15 – 24 FTE AHP Where another AHM is Grade 3 and/or at least 26 is Chief Grade 5, the 4 and/or 26 – 27 other Grade 5 or 6, the AHM other staff Chief Grade 3 would staff Grade 4 must be be reclassified to reclassified to the Chief Grade 4 Grade 4 Year 4 increment if they are at a lower increment in Grade 4.</p><p>Chief 25 – 39 FTE AHP Reclassification is not AHM Grade 25 – 39 FTE AHP Reclassification is not Grade 4 and/or at least 28 applicable as there 4 and/or at 28 – 45 applicable. other staff can be no allied Chief other staff two Grades or more above the Chief Grade 4</p><p>Chief 40 – 85 FTE AHP Reclassification is not AHM Grade 40 – 85 FTE AHP Reclassification is not Grade 5 and/or at least 46 applicable as there 5 and/or 46 – 90 other applicable. other staff can be no allied Chief staff two Grades or more above the Chief Grade 5</p><p>Chief 86 or more FTE Reclassification is not AHM Grade 86 or more FTE AHP Reclassification is not Grade 5 AHP and/or at applicable as there 6 and/or 91 or more applicable. least 91 other staff can be no allied Chief other staff two Grades or more above the Chief Grade 5</p><p>In the table above: • AHP means Employees covered by this Agreement, the 2011 Agreement, the 2016 Agreement and/or the 2020 Agreement; • Chief means a Chief as defined in the 2011 Agreement; • 2011 Agreement, 2016 Agreement, 2020 Agreement and Agreement has the same meaning as in <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4</a>; and • FTE means Full-Time Employees, which is determined in accordance with subclause 86.1 of the 2020 Agreement, subclause 86.1 of the 2016 Agreement and/or subclause 29.1 of the 2011 Agreement.</p><p><strong>87.4</strong> Management Arrangement</p><p><strong>(a)</strong> Clinical and service outcomes, management of the service-wide program, and departmental budgets will be the responsibility of the Senior Allied Health Manager.</p><p><strong>(b)</strong> The Senior Allied Health Manager/Allied Health Manager at a multi-campus hospital will also ensure that all relevant Employees at a campus will be managed, and clinically guided by an appropriately graded Employee who principally works at that campus.</p>',35)])])}const g=a(n,[["render",o]]);export{f as __pageData,g as default};
